import mysql.connector
import os
import sys

def secure_load_data_infile(connection, file_path, table_name, columns):
    try:
        # Validate file path
        if not os.path.isfile(file_path):
            raise FileNotFoundError(f"File not found: {file_path}")
        
        # Validate table name (basic sanitization)
        if not table_name.replace('_', '').isalnum():
            raise ValueError("Invalid table name")
        
        # Validate columns
        if not columns or not all(col.replace('_', '').isalnum() for col in columns):
            raise ValueError("Invalid column names")
        
        # Prepare SQL statement with parameterized table name
        sql = f"LOAD DATA INFILE %s INTO TABLE `{table_name}` FIELDS TERMINATED BY ',' LINES TERMINATED BY '\\n' IGNORE 1 ROWS"
        
        cursor = connection.cursor()
        cursor.execute(sql, (file_path,))
        connection.commit()
        cursor.close()
        
        print(f"Successfully imported data from {file_path} into table {table_name}")
        
    except Exception as e:
        print(f"Error importing data: {str(e)}")
        connection.rollback()

def main():
    try:
        # Get user input
        file_path = input("Enter the path to the CSV file: ").strip()
        table_name = input("Enter the target table name: ").strip()
        
        # MySQL connection parameters
        config = {
            'user': 'your_username',
            'password': 'your_password',
            'host': 'localhost',
            'database': 'your_database',
            'autocommit': False,
            'allow_local_infile': True,
            'raise_on_warnings': True
        }
        
        # Establish connection
        connection = mysql.connector.connect(**config)
        
        # Enable local_infile
        cursor = connection.cursor()
        cursor.execute("SET GLOBAL local_infile = 'ON'")
        cursor.close()
        
        # Import data
        secure_load_data_infile(connection, file_path, table_name, [])
        
        connection.close()
        
    except mysql.connector.Error as e:
        print(f"Database error: {e}")
    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    main()